17	/** Grid position on a 12-column CSS Grid */
18	export interface GridPos {
19	  x: number;
20	  y: number;
21	  w: number;
22	  h: number;
23	}
24	
25	/** Reference to a datasource instance */
26	export interface DatasourceRef {
27	  type: DatasourceType;
28	  uid: string;
29	}
30	
31	/** A query bound to a specific datasource */
32	export interface PanelQuery {
33	  refId: string;
34	  datasource: DatasourceRef;
35	  query: unknown;
36	}
37	
38	/** Dashboard tab for organizing panels into groups */
39	export interface DashboardTab {
40	  id: string;
41	  title: string;
42	  order: number;
43	}
44	
45	/** A panel is a single visualization unit on the dashboard */
46	export interface DashboardPanel {
47	  id: string;
48	  type: PanelType;
49	  title: string;
50	  description?: string;
51	  gridPos: GridPos;
52	  datasource: DatasourceRef;
53	  queries: PanelQuery[];
54	  options: Record<string, unknown>;
55	  fieldConfig?: FieldConfig;
56	  schemaVersion?: number;
57	  timeFrom?: string;
58	  transparent?: boolean;
59	  repeatVariable?: string;
60	  collapsed?: boolean;
61	  tabId?: string;
62	}
63	
64	/** Field display configuration */
65	export interface FieldConfig {
66	  defaults?: FieldConfigDefault;
67	  overrides?: FieldConfigOverride[];
68	}
69	
70	export interface FieldConfigDefault {
71	  unit?: string;
72	  decimals?: number;
73	  displayName?: string;
74	  color?: string;
75	  thresholds?: ThresholdConfig;
76	}
77	
78	export interface FieldConfigOverride {
79	  matcher: { id: string; value: string };
80	  properties: Record<string, unknown>;
81	}
82	
83	export interface ThresholdConfig {
84	  mode: "absolute" | "percentage";
85	  steps: { value: number; color: string }[];
86	}
87	
88	/** Dashboard variable definition */
89	export interface DashboardVariable {
90	  id: string;
91	  name: string;
92	  label?: string;
93	  type: "query" | "custom" | "textbox" | "datasource" | "interval";
94	  defaultValue?: unknown;
95	  current?: { value: unknown; text: string };
96	  options?: { value: unknown; text: string; selected: boolean }[];
97	  datasource?: DatasourceRef;
98	  query?: string;
99	  multi?: boolean;
100	  includeAll?: boolean;
101	  /** Parent variable IDs this depends on (cascading) */
102	  dependsOn?: string[];
103	}
104	
105	/** Dashboard-level time range */
106	export interface DashboardTimeRange {
107	  from: string;
108	  to: string;
109	}
110	
111	/** A dashboard is a collection of panels arranged on a grid */
112	export interface Dashboard {
113	  id: string;
114	  uid: string;
115	  title: string;
116	  description?: string;
117	  tags: string[];
118	  variables: DashboardVariable[];
119	  timeRange: DashboardTimeRange;
120	  refreshInterval?: string;
