56	/**
57	 * Renders the Patterns tab showing logtype occurrence statistics
58	 * and shared node warnings.
59	 */
60	const PatternsTab = () => {
61	    const [search, setSearch] = useState("");
62	    const [expandedLogtype, setExpandedLogtype] = useState<string | null>(null);
63	
64	    const {data, isLoading, error} = useQuery({
65	        queryKey: ["logtype-stats"],
66	        queryFn: async () => {
67	            const res = await api.api.logtype_stats.$get({
68	                query: {archive_id: "latest"},
69	            });
70	            return res.json() as Promise<LogtypeStatsResponse>;
71	        },
72	    });
73	
74	    if (isLoading) {
75	        return <div className="p-4 text-sm text-muted-foreground">Loading logtype stats...</div>;
76	    }
77	
78	    if (error) {
79	        return <div className="p-4 text-sm text-red-600">Error: {error.message}</div>;
80	    }
81	
82	    if (!data) {
83	        return <div className="p-4 text-sm text-muted-foreground">No logtype data available.</div>;
84	    }
85	
86	    const filtered = data.logtypes.filter(
87	        (lt) =>
88	            lt.logtype.toLowerCase().includes(search.toLowerCase()) ||
89	            lt.template.toLowerCase().includes(search.toLowerCase()),
90	    );
91	
92	    return (
93	        <div className="flex flex-col gap-4">
94	            {0 < data.sharedNodeWarnings.length && (
95	                <div className="rounded-md border border-yellow-300 bg-yellow-50 p-3">
96	                    <p className="text-sm font-medium text-yellow-800">Shared Node Warnings</p>
97	                    <ul className="mt-1 list-inside list-disc text-sm text-yellow-700">
98	                        {data.sharedNodeWarnings.map((w, i) => (
99	                            <li key={i}>{w.message}</li>
100	                        ))}
101	                    </ul>
102	                </div>
103	            )}
104	
105	            <Input
106	                placeholder="Search logtypes..."
107	                value={search}
108	                onChange={(e) => setSearch(e.target.value)}
109	            />
110	
111	            <div className="text-sm text-muted-foreground">
112	                {filtered.length} logtype{1 !== filtered.length ? "s" : ""} | {data.totalCount.toLocaleString()} total events
113	            </div>
114	
115	            <ScrollArea className="h-[calc(100vh-320px)]">
116	                <Table>
117	                    <TableHeader>
118	                        <TableRow>
119	                            <TableHead className="w-12"/>
120	                            <TableHead>Logtype</TableHead>
121	                            <TableHead className="text-right">Count</TableHead>
122	                            <TableHead>Template</TableHead>
123	                        </TableRow>
124	                    </TableHeader>
125	                    <TableBody>
126	                        {filtered.map((lt) => {
127	                            const isExpanded = expandedLogtype === lt.logtype;
128	                            return (
129	                                <Collapsible
130	                                    key={lt.logtype}
131	                                    open={isExpanded}
132	                                    onOpenChange={() => setExpandedLogtype(isExpanded ? null : lt.logtype)}
133	                                    asChild
134	                                >
135	                                    <TableRow className="cursor-pointer">
136	                                        <TableCell>
137	                                            <CollapsibleTrigger asChild>
138	                                                <button className="text-muted-foreground hover:text-foreground">
139	                                                    {isExpanded ? "▼" : "▶"}
140	                                                </button>
141	                                            </CollapsibleTrigger>
142	                                        </TableCell>
143	                                        <TableCell className="font-mono text-xs">{lt.logtype}</TableCell>
144	                                        <TableCell className="text-right">{lt.count.toLocaleString()}</TableCell>
145	                                        <TableCell className="max-w-md truncate font-mono text-xs">
146	                                            {lt.template}
147	                                        </TableCell>
148	                                    </TableRow>
149	                                    {isExpanded && (
150	                                        <TableRow>
151	                                            <TableCell colSpan={4} className="bg-muted/50 px-8 py-3">
152	                                                <CollapsibleContent>
153	                                                    <div className="space-y-2">
154	                                                        <p className="text-xs font-medium">Variables ({lt.variables.length})</p>
155	                                                        <div className="flex flex-wrap gap-2">
156	                                                            {lt.variables.map((v) => (
157	                                                                <Badge
158	                                                                    key={v.index}
159	                                                                    variant="outline"
160	                                                                    className={VARIABLE_TYPE_COLORS[v.type] ?? ""}
161	                                                                >
162	                                                                    #{v.index} {v.type}
163	                                                                </Badge>
164	                                                            ))}
165	                                                        </div>
166	                                                        <Separator/>
167	                                                        <p className="text-xs text-muted-foreground">
168	                                                            Template: <code className="text-foreground">{lt.template}</code>
169	                                                        </p>
170	                                                    </div>
171	                                                </CollapsibleContent>
172	                                            </TableCell>
173	                                        </TableRow>
174	                                    )}
175	                                </Collapsible>
176	                            );
177	                        })}
178	                    </TableBody>
179	                </Table>
180	            </ScrollArea>
181	        </div>
182	    );
183	};
