21	const api = hc<AppType>("/");
22	
23	const TYPE_ICONS: Record<string, string> = {
24	    string: "Aa",
25	    int: "#",
26	    float: "~",
27	    object: "{}",
28	};
29	
30	const TYPE_COLORS: Record<string, string> = {
31	    string: "bg-green-100 text-green-800",
32	    int: "bg-blue-100 text-blue-800",
33	    float: "bg-purple-100 text-purple-800",
34	    object: "bg-gray-100 text-gray-800",
35	};
