37	/**
38	 * Renders a single node in the schema tree, recursively.
39	 */
40	const SchemaTreeNodeItem = ({
41	    node,
42	    depth = 0,
43	}: {
44	    node: SchemaTreeNode;
45	    depth?: number;
46	}) => {
47	    const [isOpen, setIsOpen] = useState(depth < 2);
48	    const hasChildren = 0 < node.children.length;
49	
50	    return (
51	        <div>
52	            <Collapsible open={isOpen} onOpenChange={setIsOpen}>
53	                <div
54	                    className="flex items-center gap-2 rounded-sm px-2 py-1 hover:bg-muted/50"
55	                    style={{paddingLeft: `${depth * 20 + 8}px`}}
56	                >
57	                    {hasChildren ? (
58	                        <CollapsibleTrigger asChild>
59	                            <button className="w-4 text-muted-foreground hover:text-foreground">
60	                                {isOpen ? "▼" : "▶"}
61	                            </button>
62	                        </CollapsibleTrigger>
63	                    ) : (
64	                        <span className="w-4"/>
65	                    )}
66	                    <Badge
67	                        variant="outline"
68	                        className={`text-[10px] ${TYPE_COLORS[node.type] ?? ""}`}
69	                    >
70	                        {TYPE_ICONS[node.type] ?? "?"}
71	                    </Badge>
72	                    <span className="font-mono text-sm">{node.key}</span>
73	                    <span className="text-xs text-muted-foreground">
74	                        ({node.count.toLocaleString()})
75	                    </span>
76	                </div>
77	                {hasChildren && (
78	                    <CollapsibleContent>
79	                        {node.children.map((child) => (
80	                            <SchemaTreeNodeItem
81	                                key={child.id}
82	                                node={child}
83	                                depth={depth + 1}
84	                            />
85	                        ))}
86	                    </CollapsibleContent>
87	                )}
88	            </Collapsible>
89	        </div>
90	    );
91	};
